namespace sv_85a4b5b6cbd0411cac753b02b6217e68.Models;

public record UserProfile(string DisplayName, string Email, string AvatarUrl, string Bio);
public record NotificationPrefs(bool EmailNotifications, bool PushNotifications, bool WeeklyDigest, List<string> MutedChannels);
public record SecuritySettings(bool TwoFactorEnabled, DateTime? LastPasswordChange, List<ActiveSession> Sessions);
public record ActiveSession(string Id, string Device, string Location, DateTime LastActive);
public record AppearanceSettings(string Theme, string FontSize, string Language, bool CompactMode);

public interface ISettingsService
{
    Task<UserProfile> GetProfileAsync();
    Task SaveProfileAsync(UserProfile profile);
    Task<NotificationPrefs> GetNotificationPrefsAsync();
    Task SaveNotificationPrefsAsync(NotificationPrefs prefs);
    Task<SecuritySettings> GetSecuritySettingsAsync();
    Task ChangePasswordAsync(string currentPassword, string newPassword);
    Task RevokeSessionAsync(string sessionId);
    Task<AppearanceSettings> GetAppearanceAsync();
    Task SaveAppearanceAsync(AppearanceSettings settings);
}

@namespace sv_85a4b5b6cbd0411cac753b02b6217e68.Components.Pages.Settings

<nav class="settings-sidebar">
    <h5 class="px-3 py-2 text-muted text-uppercase fw-semibold small">Settings</h5>
    <ul class="nav flex-column">
        @foreach (var section in Sections)
        {
            <li class="nav-item">
                <button class="nav-link w-100 text-start @(section == ActiveSection ? "active" : "")"
                        @onclick="() => OnSectionChanged.InvokeAsync(section)">
                    <span class="me-2">@GetIcon(section)</span>
                    @section
                </button>
            </li>
        }
    </ul>
</nav>

@code {
    [Parameter] public string ActiveSection { get; set; } = "Profile";
    [Parameter] public EventCallback<string> OnSectionChanged { get; set; }

    private static readonly string[] Sections = ["Profile", "Notifications", "Security", "Appearance"];

    private static string GetIcon(string section) => section switch
    {
        "Profile" => "👤",
        "Notifications" => "🔔",
        "Security" => "🔒",
        "Appearance" => "🎨",
        _ => "⚙️"
    };
}

.settings-sidebar {
    min-width: 220px;
    background: #f8f9fa;
    border-right: 1px solid #dee2e6;
    padding-top: 1rem;
    height: 100%;
}

.nav-link {
    color: #495057;
    border: none;
    background: none;
    padding: 0.6rem 1rem;
    border-radius: 0;
    border-left: 3px solid transparent;
    transition: all 0.15s ease;
}

.nav-link:hover {
    background: #e9ecef;
    color: #212529;
}

.nav-link.active {
    background: #e7f1ff;
    color: #0d6efd;
    border-left-color: #0d6efd;
    font-weight: 600;
}

@namespace sv_85a4b5b6cbd0411cac753b02b6217e68.Components.Pages.Settings

<div class="profile-section">
    <h4 class="mb-4">Profile Settings</h4>

    <div class="row">
        <div class="col-md-8">
            <div class="mb-3">
                <label class="form-label fw-semibold">Display Name</label>
                <input type="text" class="form-control" @bind="DisplayName" />
            </div>
            <div class="mb-3">
                <label class="form-label fw-semibold">Email</label>
                <input type="email" class="form-control" @bind="Email" />
            </div>
            <div class="mb-3">
                <label class="form-label fw-semibold">Bio</label>
                <textarea class="form-control" rows="4" @bind="Bio"></textarea>
            </div>
        </div>

        <div class="col-md-4">
            <div class="avatar-preview text-center p-3">
                <div class="avatar-frame mb-2">
                    @if (!string.IsNullOrWhiteSpace(AvatarUrl))
                    {
                        <img src="@AvatarUrl" alt="Avatar" class="rounded-circle" style="width:100px;height:100px;object-fit:cover;" />
                    }
                    else
                    {
                        <div class="avatar-placeholder rounded-circle d-flex align-items-center justify-content-center"
                             style="width:100px;height:100px;background:#dee2e6;margin:0 auto;">
                            <span style="font-size:2.5rem;">👤</span>
                        </div>
                    }
                </div>
                <small class="text-muted text-break">@(string.IsNullOrWhiteSpace(AvatarUrl) ? "No avatar URL set" : AvatarUrl)</small>
            </div>
        </div>
    </div>

    <div class="d-flex gap-2 mt-3">
        <button class="btn btn-primary" @onclick="HandleSave" disabled="@IsSaving">
            @if (IsSaving)
            {
                <span class="spinner-border spinner-border-sm me-1"></span>
            }
            Save Changes
        </button>
        <button class="btn btn-outline-secondary" @onclick="HandleDiscard">Discard Changes</button>
    </div>
</div>

@code {
    [Parameter] public UserProfile? Profile { get; set; }
    [Parameter] public EventCallback<UserProfile> OnSave { get; set; }

    private string DisplayName { get; set; } = "";
    private string Email { get; set; } = "";
    private string AvatarUrl { get; set; } = "";
    private string Bio { get; set; } = "";
    private bool IsSaving { get; set; }

    protected override void OnParametersSet()
    {
        if (Profile is not null && !_initialized)
        {
            LoadFromProfile(Profile);
            _initialized = true;
        }
    }

    private bool _initialized;

    private void LoadFromProfile(UserProfile profile)
    {
        DisplayName = profile.DisplayName;
        Email = profile.Email;
        AvatarUrl = profile.AvatarUrl;
        Bio = profile.Bio;
    }

    private async Task HandleSave()
    {
        IsSaving = true;
        var updated = new UserProfile(DisplayName, Email, AvatarUrl, Bio);
        await OnSave.InvokeAsync(updated);
        IsSaving = false;
    }

    private void HandleDiscard()
    {
        if (Profile is not null)
        {
            LoadFromProfile(Profile);
        }
    }
}

@namespace sv_85a4b5b6cbd0411cac753b02b6217e68.Components.Pages.Settings

<div class="notifications-section">
    <h4 class="mb-4">Notification Preferences</h4>

    <div class="card mb-4">
        <div class="card-body">
            <h6 class="card-title mb-3">General</h6>

            <div class="form-check form-switch mb-3">
                <input class="form-check-input" type="checkbox" id="emailNotif" @bind="EmailNotifications" />
                <label class="form-check-label" for="emailNotif">
                    <strong>Email Notifications</strong>
                    <br /><small class="text-muted">Receive notifications via email</small>
                </label>
            </div>

            <div class="form-check form-switch mb-3">
                <input class="form-check-input" type="checkbox" id="pushNotif" @bind="PushNotifications" />
                <label class="form-check-label" for="pushNotif">
                    <strong>Push Notifications</strong>
                    <br /><small class="text-muted">Receive browser push notifications</small>
                </label>
            </div>

            <div class="form-check form-switch mb-3">
                <input class="form-check-input" type="checkbox" id="weeklyDigest" @bind="WeeklyDigest" />
                <label class="form-check-label" for="weeklyDigest">
                    <strong>Weekly Digest</strong>
                    <br /><small class="text-muted">Get a weekly summary of activity</small>
                </label>
            </div>
        </div>
    </div>

    <div class="card mb-4">
        <div class="card-body">
            <h6 class="card-title mb-3">Muted Channels</h6>
            @if (AvailableChannels.Count == 0)
            {
                <p class="text-muted">No channels available.</p>
            }
            else
            {
                @foreach (var channel in AvailableChannels)
                {
                    <div class="form-check mb-2">
                        <input class="form-check-input" type="checkbox" id="@($"ch-{channel}")"
                               checked="@MutedSet.Contains(channel)"
                               @onchange="e => ToggleMute(channel, (bool)(e.Value ?? false))" />
                        <label class="form-check-label" for="@($"ch-{channel}")">@channel</label>
                    </div>
                }
            }
        </div>
    </div>

    <button class="btn btn-primary" @onclick="HandleSave" disabled="@IsSaving">
        @if (IsSaving)
        {
            <span class="spinner-border spinner-border-sm me-1"></span>
        }
        Save Preferences
    </button>
</div>

@code {
    [Parameter] public NotificationPrefs? Prefs { get; set; }
    [Parameter] public EventCallback<NotificationPrefs> OnSave { get; set; }

    private bool EmailNotifications { get; set; }
    private bool PushNotifications { get; set; }
    private bool WeeklyDigest { get; set; }
    private HashSet<string> MutedSet { get; set; } = new();
    private bool IsSaving { get; set; }

    // Channels available in the system for muting
    private List<string> AvailableChannels { get; set; } = ["general", "announcements", "engineering", "design", "marketing", "support"];

    private bool _initialized;

    protected override void OnParametersSet()
    {
        if (Prefs is not null && !_initialized)
        {
            EmailNotifications = Prefs.EmailNotifications;
            PushNotifications = Prefs.PushNotifications;
            WeeklyDigest = Prefs.WeeklyDigest;
            MutedSet = new HashSet<string>(Prefs.MutedChannels);
            _initialized = true;
        }
    }

    private void ToggleMute(string channel, bool isMuted)
    {
        if (isMuted)
            MutedSet.Add(channel);
        else
            MutedSet.Remove(channel);
    }

    private async Task HandleSave()
    {
        IsSaving = true;
        var updated = new NotificationPrefs(EmailNotifications, PushNotifications, WeeklyDigest, MutedSet.ToList());
        await OnSave.InvokeAsync(updated);
        IsSaving = false;
    }
}

@namespace sv_85a4b5b6cbd0411cac753b02b6217e68.Components.Pages.Settings

<div class="card mb-4">
    <div class="card-header d-flex justify-content-between align-items-center"
         style="cursor:pointer;" @onclick="() => IsExpanded = !IsExpanded">
        <h6 class="mb-0">🔑 Change Password</h6>
        <span>@(IsExpanded ? "▲" : "▼")</span>
    </div>
    @if (IsExpanded)
    {
        <div class="card-body">
            @if (!string.IsNullOrEmpty(ErrorMessage))
            {
                <div class="alert alert-danger alert-dismissible fade show" role="alert">
                    @ErrorMessage
                    <button type="button" class="btn-close" @onclick="() => ErrorMessage = null"></button>
                </div>
            }
            @if (SuccessMessage is not null)
            {
                <div class="alert alert-success alert-dismissible fade show" role="alert">
                    @SuccessMessage
                    <button type="button" class="btn-close" @onclick="() => SuccessMessage = null"></button>
                </div>
            }

            <div class="mb-3">
                <label class="form-label">Current Password</label>
                <input type="password" class="form-control" @bind="CurrentPassword" style="max-width:400px;" />
            </div>
            <div class="mb-3">
                <label class="form-label">New Password</label>
                <input type="password" class="form-control" @bind="NewPassword" style="max-width:400px;" />
            </div>
            <div class="mb-3">
                <label class="form-label">Confirm New Password</label>
                <input type="password" class="form-control" @bind="ConfirmPassword" style="max-width:400px;" />
            </div>
            <button class="btn btn-warning" @onclick="HandleChangePassword" disabled="@IsSubmitting">
                @if (IsSubmitting)
                {
                    <span class="spinner-border spinner-border-sm me-1"></span>
                }
                Update Password
            </button>
        </div>
    }
</div>

@code {
    [Parameter] public EventCallback<(string CurrentPassword, string NewPassword)> OnChangePassword { get; set; }

    private string CurrentPassword { get; set; } = "";
    private string NewPassword { get; set; } = "";
    private string ConfirmPassword { get; set; } = "";
    private bool IsExpanded { get; set; }
    private bool IsSubmitting { get; set; }
    private string? ErrorMessage { get; set; }
    private string? SuccessMessage { get; set; }

    private async Task HandleChangePassword()
    {
        ErrorMessage = null;
        SuccessMessage = null;

        if (string.IsNullOrWhiteSpace(CurrentPassword) || string.IsNullOrWhiteSpace(NewPassword))
        {
            ErrorMessage = "All password fields are required.";
            return;
        }

        if (NewPassword != ConfirmPassword)
        {
            ErrorMessage = "New password and confirmation do not match.";
            return;
        }

        if (NewPassword.Length < 8)
        {
            ErrorMessage = "New password must be at least 8 characters.";
            return;
        }

        IsSubmitting = true;
        try
        {
            await OnChangePassword.InvokeAsync((CurrentPassword, NewPassword));
            SuccessMessage = "Password updated successfully.";
            CurrentPassword = "";
            NewPassword = "";
            ConfirmPassword = "";
        }
        catch (Exception ex)
        {
            ErrorMessage = $"Failed to update password: {ex.Message}";
        }
        finally
        {
            IsSubmitting = false;
        }
    }
}

