    private bool _showRevokeDialog;
    private ActiveSession? _sessionToRevoke;
    private bool _initialized;

    protected override void OnParametersSet()
    {
        if (Settings is not null && !_initialized)
        {
            TwoFactorEnabled = Settings.TwoFactorEnabled;
            _initialized = true;
        }
    }

    private void ShowRevokeDialog(ActiveSession session)
    {
        _sessionToRevoke = session;
        _showRevokeDialog = true;
    }

    private async Task HandleRevokeConfirmed(string sessionId)
