{"path": "/tmp/sv-85a4b5b6cbd0411cac753b02b6217e68/Components/Pages/Settings/ChangePasswordPanel.razor", "file_text": "@namespace sv_85a4b5b6cbd0411cac753b02b6217e68.Components.Pages.Settings

<div class="card mb-4">
    <div class="card-header d-flex justify-content-between align-items-center"
         style="cursor:pointer;" @onclick="() => IsExpanded = !IsExpanded">
        <h6 class="mb-0">🔑 Change Password</h6>
        <span>@(IsExpanded ? "▲" : "▼")</span>
    </div>
    @if (IsExpanded)
    {
        <div class="card-body">
            @if (!string.IsNullOrEmpty(ErrorMessage))
            {
                <div class="alert alert-danger alert-dismissible fade show" role="alert">
                    @ErrorMessage
                    <button type="button" class="btn-close" @onclick="() => ErrorMessage = null"></button>
                </div>
            }
            @if (SuccessMessage is not null)
            {
                <div class="alert alert-success alert-dismissible fade show" role="alert">
                    @SuccessMessage
                    <button type="button" class="btn-close" @onclick="() => SuccessMessage = null"></button>
                </div>
            }

            <div class="mb-3">
                <label class="form-label">Current Password</label>
                <input type="password" class="form-control" @bind="CurrentPassword" style="max-width:400px;" />
            </div>
            <div class="mb-3">
                <label class="form-label">New Password</label>
                <input type="password" class="form-control" @bind="NewPassword" style="max-width:400px;" />
            </div>
            <div class="mb-3">
                <label class="form-label">Confirm New Password</label>
                <input type="password" class="form-control" @bind="ConfirmPassword" style="max-width:400px;" />
            </div>
            <button class="btn btn-warning" @onclick="HandleChangePassword" disabled="@IsSubmitting">
                @if (IsSubmitting)
                {
                    <span class="spinner-border spinner-border-sm me-1"></span>
                }
                Update Password
            </button>
        </div>
    }
</div>

@code {
    [Parameter] public EventCallback<(string CurrentPassword, string NewPassword)> OnChangePassword { get; set; }

    private string CurrentPassword { get; set; } = "";
    private string NewPassword { get; set; } = "";
    private string ConfirmPassword { get; set; } = "";
    private bool IsExpanded { get; set; }
    private bool IsSubmitting { get; set; }
    private string? ErrorMessage { get; set; }
    private string? SuccessMessage { get; set; }

    private async Task HandleChangePassword()
    {
        ErrorMessage = null;
        SuccessMessage = null;

        if (string.IsNullOrWhiteSpace(CurrentPassword) || string.IsNullOrWhiteSpace(NewPassword))
        {
            ErrorMessage = "All password fields are required.";
            return;
        }

        if (NewPassword != ConfirmPassword)
        {
            ErrorMessage = "New password and confirmation do not match.";
            return;
        }

        if (NewPassword.Length < 8)
        {
            ErrorMessage = "New password must be at least 8 characters.";
            return;
        }

        IsSubmitting = true;
        try
        {
            await OnChangePassword.InvokeAsync((CurrentPassword, NewPassword));
            SuccessMessage = "Password updated successfully.";
            CurrentPassword = "";
            NewPassword = "";
            ConfirmPassword = "";
        }
        catch (Exception ex)
        {
            ErrorMessage = $"Failed to update password: {ex.Message}";
        }
        finally
        {
            IsSubmitting = false;
        }
    }
}
"}

{"path": "/tmp/sv-85a4b5b6cbd0411cac753b02b6217e68/Components/Pages/Settings/RevokeSessionDialog.razor", "file_text": "@namespace sv_85a4b5b6cbd0411cac753b02b6217e68.Components.Pages.Settings

@if (IsVisible)
{
    <div class="modal-backdrop fade show"></div>
    <div class="modal fade show d-block" tabindex="-1" role="dialog">
        <div class="modal-dialog modal-dialog-centered" role="document">
            <div class="modal-content">
                <div class="modal-header">
                    <h5 class="modal-title">Revoke Session</h5>
                    <button type="button" class="btn-close" @onclick="HandleCancel"></button>
                </div>
                <div class="modal-body">
                    <p>Are you sure you want to revoke this session?</p>
                    @if (Session is not null)
                    {
                        <div class="bg-light rounded p-3">
                            <strong>@Session.Device</strong><br />
                            <small class="text-muted">@Session.Location — Last active @Session.LastActive.ToString("g")</small>
                        </div>
                    }
                    <p class="mt-3 text-muted small">This will sign the device out immediately.</p>
                </div>
                <div class="modal-footer">
                    <button type="button" class="btn btn-secondary" @onclick="HandleCancel">Cancel</button>
                    <button type="button" class="btn btn-danger" @onclick="HandleConfirm" disabled="@IsRevoking">
                        @if (IsRevoking)
                        {
                            <span class="spinner-border spinner-border-sm me-1"></span>
                        }
                        Revoke Session
                    </button>
                </div>
            </div>
        </div>
    </div>
}

@code {
    [Parameter] public bool IsVisible { get; set; }
    [Parameter] public ActiveSession? Session { get; set; }
    [Parameter] public EventCallback<string> OnConfirm { get; set; }
    [Parameter] public EventCallback OnCancel { get; set; }

    private bool IsRevoking { get; set; }

    private async Task HandleConfirm()
    {
        if (Session is null) return;
        IsRevoking = true;
        await OnConfirm.InvokeAsync(Session.Id);
        IsRevoking = false;
    }

    private async Task HandleCancel()
    {
        await OnCancel.InvokeAsync();
    }
}
"}

{"path": "/tmp/sv-85a4b5b6cbd0411cac753b02b6217e68/Components/Pages/Settings/SecuritySection.razor", "file_text": "@namespace sv_85a4b5b6cbd0411cac753b02b6217e68.Components.Pages.Settings

<div class="security-section">
    <h4 class="mb-4">Security Settings</h4>

    <ChangePasswordPanel OnChangePassword="OnChangePassword" />

    <div class="card mb-4">
        <div class="card-body">
            <div class="d-flex justify-content-between align-items-center">
                <div>
                    <h6 class="mb-1">🛡️ Two-Factor Authentication</h6>
                    <small class="text-muted">Add an extra layer of security to your account</small>
                </div>
                <div class="d-flex align-items-center gap-2">
                    <span class="badge @(TwoFactorEnabled ? "bg-success" : "bg-secondary")">
                        @(TwoFactorEnabled ? "Enabled" : "Disabled")
                    </span>
                    <div class="form-check form-switch mb-0">
                        <input class="form-check-input" type="checkbox" @bind="TwoFactorEnabled" />
                    </div>
                </div>
            </div>
        </div>
    </div>

    @if (Settings?.LastPasswordChange is not null)
    {
        <div class="mb-4">
            <small class="text-muted">Last password change: @Settings.LastPasswordChange.Value.ToString("MMMM dd, yyyy")</small>
        </div>
    }

    <div class="card mb-4">
        <div class="card-header">
            <h6 class="mb-0">📱 Active Sessions</h6>
        </div>
        <div class="card-body p-0">
            @if (Settings?.Sessions is { Count: > 0 })
            {
                <div class="table-responsive">
                    <table class="table table-hover mb-0">
                        <thead class="table-light">
                            <tr>
                                <th>Device</th>
                                <th>Location</th>
                                <th>Last Active</th>
                                <th class="text-end">Action</th>
                            </tr>
                        </thead>
                        <tbody>
                            @foreach (var session in Settings.Sessions)
                            {
                                var isCurrent = session == Settings.Sessions[0];
                                <tr>
                                    <td>
                                        @session.Device
                                        @if (isCurrent)
                                        {
                                            <span class="badge bg-info ms-1">Current</span>
                                        }
                                    </td>
                                    <td>@session.Location</td>
                                    <td>@session.LastActive.ToString("g")</td>
                                    <td class="text-end">
                                        @if (!isCurrent)
                                        {
                                            <button class="btn btn-outline-danger btn-sm"
                                                    @onclick="() => ShowRevokeDialog(session)">
                                                Revoke
                                            </button>
                                        }
                                    </td>
                                </tr>
                            }
                        </tbody>
                    </table>
                </div>
            }
            else
            {
                <div class="p-3 text-muted">No active sessions found.</div>
            }
        </div>
    </div>

    <RevokeSessionDialog IsVisible="_showRevokeDialog"
                         Session="_sessionToRevoke"
                         OnConfirm="HandleRevokeConfirmed"
                         OnCancel="HandleRevokeCancelled" />
</div>

@code {
    [Parameter] public SecuritySettings? Settings { get; set; }
    [Parameter] public EventCallback<(string CurrentPassword, string NewPassword)> OnChangePassword { get; set; }
    [Parameter] public EventCallback<string> OnRevokeSession { get; set; }

    private bool TwoFactorEnabled { get; set; }
    private bool _showRevokeDialog;
    private ActiveSession? _sessionToRevoke;
    private bool _initialized;

    protected override void OnParametersSet()
    {
        if (Settings is not null && !_initialized)
        {
            TwoFactorEnabled = Settings.TwoFactorEnabled;
            _initialized = true;
        }
    }

    private void ShowRevokeDialog(ActiveSession session)
    {
        _sessionToRevoke = session;
        _showRevokeDialog = true;
    }

    private async Task HandleRevokeConfirmed(string sessionId)
    {
        await OnRevokeSession.InvokeAsync(sessionId);
        _showRevokeDialog = false;
        _sessionToRevoke = null;
    }

    private void HandleRevokeCancelled()
    {
        _showRevokeDialog = false;
        _sessionToRevoke = null;
    }
}
"}

{"path": "/tmp/sv-85a4b5b6cbd0411cac753b02b6217e68/Components/Pages/Settings/AppearanceSection.razor", "file_text": "@namespace sv_85a4b5b6cbd0411cac753b02b6217e68.Components.Pages.Settings

<div class="appearance-section">
    <h4 class="mb-4">Appearance Settings</h4>

    <div class="row">
        <div class="col-md-7">
            <div class="card mb-4">
                <div class="card-body">
                    <h6 class="card-title mb-3">🎨 Theme</h6>
                    @foreach (var theme in new[] { "Light", "Dark", "System" })
                    {
                        <div class="form-check mb-2">
                            <input class="form-check-input" type="radio" name="theme"
                                   id="@($"theme-{theme}")"
                                   value="@theme"
                                   checked="@(Theme == theme)"
                                   @onchange="() => Theme = theme" />
                            <label class="form-check-label" for="@($"theme-{theme}")">@theme</label>
                        </div>
                    }
                </div>
            </div>

            <div class="card mb-4">
                <div class="card-body">
                    <h6 class="card-title mb-3">🔤 Font Size</h6>
                    @foreach (var size in new[] { "Small", "Medium", "Large" })
                    {
                        <div class="form-check form-check-inline">
                            <input class="form-check-input" type="radio" name="fontSize"
                                   id="@($"fs-{size}")"
                                   value="@size"
                                   checked="@(FontSize == size)"
                                   @onchange="() => FontSize = size" />
                            <label class="form-check-label" for="@($"fs-{size}")">@size</label>
                        </div>
                    }
                </div>
            </div>

            <div class="card mb-4">
                <div class="card-body">
                    <h6 class="card-title mb-3">🌐 Language</h6>
                    <select class="form-select" style="max-width:300px;"
                            value="@Language" @onchange="e => Language = e.Value?.ToString() ?? Language">
                        <option value="en">English</option>
                        <option value="es">Español</option>
                        <option value="fr">Français</option>
                        <option value="de">Deutsch</option>
                        <option value="ja">日本語</option>
                        <option value="zh">中文</option>
                    </select>
                </div>
            </div>

            <div class="card mb-4">
                <div class="card-body">
                    <div class="form-check form-switch">
                        <input class="form-check-input" type="checkbox" id="compactMode" @bind="CompactMode" />
                        <label class="form-check-label" for="compactMode">
                            <strong>Compact Mode</strong>
                            <br /><small class="text-muted">Reduce spacing and padding throughout the UI</small>
                        </label>
                    </div>
                </div>
            </div>

            <button class="btn btn-primary" @onclick="HandleSave" disabled="@IsSaving">
                @if (IsSaving)
                {
                    <span class="spinner-border spinner-border-sm me-1"></span>
                }
                Save
            </button>
        </div>

        <div class="col-md-5">
            <div class="card">
                <div class="card-header">
                    <h6 class="mb-0">Live Preview</h6>
                </div>
                <div class="card-body @PreviewBackgroundClass" style="@PreviewStyle min-height:300px; transition: all 0.2s ease;">
                    <div class="@PreviewTextClass">
                        <h5 style="@PreviewFontStyle">Dashboard</h5>
                        <p style="@PreviewFontStyle" class="@(CompactMode ? "mb-1" : "mb-3")">
                            Welcome back! Here's what's happening today.
                        </p>
                        <div class="@(CompactMode ? "p-2" : "p-3") rounded @PreviewCardClass mb-2" style="@PreviewFontStyle">
                            <strong>Notifications</strong><br />
                            <span>3 unread messages</span>
                        </div>
                        <div class="@(CompactMode ? "p-2" : "p-3") rounded @PreviewCardClass" style="@PreviewFontStyle">
                            <strong>Tasks</strong><br />
                            <span>5 items due this week</span>
                        </div>
                        <div class="mt-3">
                            <span class="badge bg-primary me-1">@Theme</span>
                            <span class="badge bg-secondary me-1">@FontSize</span>
                            <span class="badge bg-info me-1">@GetLanguageLabel(Language)</span>
                            @if (CompactMode)
                            {
                                <span class="badge bg-warning">Compact</span>
                            }
                        </div>
                    </div>
                </div>
            </div>
        </div>
    </div>
</div>

@code {
    [Parameter] public AppearanceSettings? Settings { get; set; }
    [Parameter] public EventCallback<AppearanceSettings> OnSave { get; set; }

    private string Theme { get; set; } = "Light";
    private string FontSize { get; set; } = "Medium";
    private string Language { get; set; } = "en";
    private bool CompactMode { get; set; }
    private bool IsSaving { get; set; }
    private bool _initialized;

    protected override void OnParametersSet()
    {
        if (Settings is not null && !_initialized)
        {
            Theme = Settings.Theme;
            FontSize = Settings.FontSize;
            Language = Settings.Language;
            CompactMode = Settings.CompactMode;
            _initialized = true;
        }
    }

    private string PreviewBackgroundClass => Theme switch
    {
        "Dark" => "bg-dark",
        _ => "bg-white"
    };

    private string PreviewTextClass => Theme switch
    {
        "Dark" => "text-light",
        _ => "text-dark"
    };

    private string PreviewCardClass => Theme switch
    {
        "Dark" => "bg-secondary bg-opacity-25 text-light",
        _ => "bg-light"
    };

    private string PreviewStyle => Theme switch
    {
        "Dark" => "border-color: #495057 !important;",
        _ => ""
    };

    private string PreviewFontStyle => FontSize switch
    {
        "Small" => "font-size: 0.8rem;",
        "Large" => "font-size: 1.15rem;",
        _ => "font-size: 0.95rem;"
    };

    private static string GetLanguageLabel(string code) => code switch
    {
        "es" => "Español",
        "fr" => "Français",
        "de" => "Deutsch",
        "ja" => "日本語",
        "zh" => "中文",
        _ => "English"
    };

    private async Task HandleSave()
    {
        IsSaving = true;
        var updated = new AppearanceSettings(Theme, FontSize, Language, CompactMode);
        await OnSave.InvokeAsync(updated);
        IsSaving = false;
    }
}
"}

