toolArgs.file_text:
@namespace sv_85a4b5b6cbd0411cac753b02b6217e68.Components.Pages.Settings

<div class="security-section">
    <h4 class="mb-4">Security Settings</h4>

    <ChangePasswordPanel OnChangePassword="OnChangePassword" />

    <div class="card mb-4">
        <div class="card-body">
            <div class="d-flex justify-content-between align-items-center">
                <div>
                    <h6 class="mb-1">🛡️ Two-Factor Authentication</h6>
                    <small class="text-muted">Add an extra layer of security to your account</small>
                </div>
                <div class="d-flex align-items-center gap-2">
                    <span class="badge @(TwoFactorEnabled ? "bg-success" : "bg-secondary")">
                        @(TwoFactorEnabled ? "Enabled" : "Disabled")
                    </span>
                    <div class="form-check form-switch mb-0">
                        <input class="form-check-input" type="checkbox" @bind="TwoFactorEnabled" />
                    </div>
                </div>
            </div>
        </div>
    </div>

    @if (Settings?.LastPasswordChange is not null)
    {
        <div class="mb-4">
            <small class="text-muted">Last password change: @Settings.LastPasswordChange.Value.ToString("MMMM dd, yyyy")</small>
        </div>
    }

    <div class="card mb-4">
        <div class="card-header">
            <h6 class="mb-0">📱 Active Sessions</h6>
        </div>
        <div class="card-body p-0">
            @if (Settings?.Sessions is { Count: > 0 })
            {
                <div class="table-responsive">
                    <table class="table table-hover mb-0">
                        <thead class="table-light">
                            <tr>
                                <th>Device</th>
                                <th>Location</th>
                                <th>Last Active</th>
                                <th class="text-end">Action</th>
                            </tr>
                        </thead>
                        <tbody>
                            @foreach (var session in Settings.Sessions)
                            {
                                var isCurrent = session == Settings.Sessions[0];
                                <tr>
                                    <td>
                                        @session.Device
                                        @if (isCurrent)
                                        {
                                            <span class="badge bg-info ms-1">Current</span>
                                        }
                                    </td>
                                    <td>@session.Location</td>
                                    <td>@session.LastActive.ToString("g")</td>
                                    <td class="text-end">
                                        @if (!isCurrent)
                                        {
                                            <button class="btn btn-outline-danger btn-sm"
                                                    @onclick="() => ShowRevokeDialog(session)">
                                                Revoke
                                            </button>
                                        }
                                    </td>
                                </tr>
                            }
                        </tbody>
                    </table>
                </div>
            }
            else
            {
                <div class="p-3 text-muted">No active sessions found.</div>
            }
        </div>
    </div>

    <RevokeSessionDialog IsVisible="_showRevokeDialog"
                         Session="_sessionToRevoke"
                         OnConfirm="HandleRevokeConfirmed"
                         OnCancel="HandleRevokeCancelled" />
</div>

@code {
    [Parameter] public SecuritySettings? Settings { get; set; }
    [Parameter] public EventCallback<(string CurrentPassword, string NewPassword)> OnChangePassword { get; set; }
    [Parameter] public EventCallback<string> OnRevokeSession { get; set; }

    private bool TwoFactorEnabled { get; set; }
    private bool _showRevokeDialog;
    private ActiveSession? _sessionToRevoke;
    private bool _initialized;

    protected override void OnParametersSet()
    {
        if (Settings is not null && !_initialized)
        {
            TwoFactorEnabled = Settings.TwoFactorEnabled;
            _initialized = true;
        }
    }

    private void ShowRevokeDialog(ActiveSession session)
    {
        _sessionToRevoke = session;
        _showRevokeDialog = true;
    }

    private async Task HandleRevokeConfirmed(string sessionId)
    {
        await OnRevokeSession.InvokeAsync(sessionId);
        _showRevokeDialog = false;
        _sessionToRevoke = null;
    }

    private void HandleRevokeCancelled()
    {
        _showRevokeDialog = false;
        _sessionToRevoke = null;
    }
}

@namespace sv_85a4b5b6cbd0411cac753b02b6217e68.Components.Pages.Settings

<div class="appearance-section">
    <h4 class="mb-4">Appearance Settings</h4>

    <div class="row">
        <div class="col-md-7">
            <div class="card mb-4">
                <div class="card-body">
                    <h6 class="card-title mb-3">🎨 Theme</h6>
                    @foreach (var theme in new[] { "Light", "Dark", "System" })
                    {
                        <div class="form-check mb-2">
                            <input class="form-check-input" type="radio" name="theme"
                                   id="@($"theme-{theme}")"
                                   value="@theme"
                                   checked="@(Theme == theme)"
                                   @onchange="() => Theme = theme" />
                            <label class="form-check-label" for="@($"theme-{theme}")">@theme</label>
                        </div>
                    }
                </div>
            </div>

            <div class="card mb-4">
                <div class="card-body">
                    <h6 class="card-title mb-3">🔤 Font Size</h6>
                    @foreach (var size in new[] { "Small", "Medium", "Large" })
                    {
                        <div class="form-check form-check-inline">
                            <input class="form-check-input" type="radio" name="fontSize"
                                   id="@($"fs-{size}")"
                                   value="@size"
                                   checked="@(FontSize == size)"
                                   @onchange="() => FontSize = size" />
                            <label class="form-check-label" for="@($"fs-{size}")">@size</label>
                        </div>
                    }
                </div>
            </div>

            <div class="card mb-4">
                <div class="card-body">
                    <h6 class="card-title mb-3">🌐 Language</h6>
                    <select class="form-select" style="max-width:300px;"
                            value="@Language" @onchange="e => Language = e.Value?.ToString() ?? Language">
                        <option value="en">English</option>
                        <option value="es">Español</option>
                        <option value="fr">Français</option>
                        <option value="de">Deutsch</option>
                        <option value="ja">日本語</option>
                        <option value="zh">中文</option>
                    </select>
                </div>
            </div>

            <div class="card mb-4">
                <div class="card-body">
                    <div class="form-check form-switch">
                        <input class="form-check-input" type="checkbox" id="compactMode" @bind="CompactMode" />
                        <label class="form-check-label" for="compactMode">
                            <strong>Compact Mode</strong>
                            <br /><small class="text-muted">Reduce spacing and padding throughout the UI</small>
                        </label>
                    </div>
                </div>
            </div>

            <button class="btn btn-primary" @onclick="HandleSave" disabled="@IsSaving">
                @if (IsSaving)
                {
                    <span class="spinner-border spinner-border-sm me-1"></span>
                }
                Save
            </button>
        </div>

        <div class="col-md-5">
            <div class="card">
                <div class="card-header">
                    <h6 class="mb-0">Live Preview</h6>
                </div>
