                    <div class="@PreviewTextClass">
                        <h5 style="@PreviewFontStyle">Dashboard</h5>
                        <p style="@PreviewFontStyle" class="@(CompactMode ? "mb-1" : "mb-3")">
                            Welcome back! Here's what's happening today.
                        </p>
                        <div class="@(CompactMode ? "p-2" : "p-3") rounded @PreviewCardClass mb-2" style="@PreviewFontStyle">
                            <strong>Notifications</strong><br />
                            <span>3 unread messages</span>
                        </div>
                        <div class="@(CompactMode ? "p-2" : "p-3") rounded @PreviewCardClass" style="@PreviewFontStyle">
                            <strong>Tasks</strong><br />
                            <span>5 items due this week</span>
                        </div>
                        <div class="mt-3">
                            <span class="badge bg-primary me-1">@Theme</span>
                            <span class="badge bg-secondary me-1">@FontSize</span>
                            <span class="badge bg-info me-1">@GetLanguageLabel(Language)</span>
                            @if (CompactMode)
                            {
