@page "/settings"
@using sv_85a4b5b6cbd0411cac753b02b6217e68.Models
@rendermode InteractiveServer

<PageTitle>Settings</PageTitle>

<div class="settings-layout">
    <SettingsSidebar ActiveSection="@_activeSection" OnSectionChanged="s => _activeSection = s" />

    <div class="settings-content p-4">
        @if (_isLoading)
        {
            <div class="d-flex justify-content-center align-items-center" style="min-height:300px;">
                <div class="spinner-border text-primary" role="status">
                    <span class="visually-hidden">Loading...</span>
                </div>
            </div>
        }
        else
        {
            @if (_toastMessage is not null)
            {
                <div class="alert @(_toastIsError ? "alert-danger" : "alert-success") alert-dismissible fade show" role="alert">
                    @_toastMessage
                    <button type="button" class="btn-close" @onclick="DismissToast"></button>
                </div>
            }

            @switch (_activeSection)
            {
                case "Profile":
                    <ProfileSection Profile="_profile" OnSave="HandleSaveProfile" />
                    break;
                case "Notifications":
                    <NotificationsSection Prefs="_notificationPrefs" OnSave="HandleSaveNotifications" />
                    break;
                case "Security":
                    <SecuritySection Settings="_securitySettings"
                                     OnChangePassword="HandleChangePassword"
                                     OnRevokeSession="HandleRevokeSession" />
                    break;
                case "Appearance":
                    <AppearanceSection Settings="_appearanceSettings" OnSave="HandleSaveAppearance" />
                    break;
            }
        }
    </div>
</div>

@code {
    [Inject] private ISettingsService SettingsService { get; set; } = default!;

    private string _activeSection = "Profile";
    private bool _isLoading = true;
    private string? _toastMessage;
    private bool _toastIsError;

    private UserProfile? _profile;
    private NotificationPrefs? _notificationPrefs;
    private SecuritySettings? _securitySettings;
    private AppearanceSettings? _appearanceSettings;

    protected override async Task OnInitializedAsync()
    {
        try
        {
            var profileTask = SettingsService.GetProfileAsync();
            var notifsTask = SettingsService.GetNotificationPrefsAsync();
            var securityTask = SettingsService.GetSecuritySettingsAsync();
            var appearanceTask = SettingsService.GetAppearanceAsync();

            await Task.WhenAll(profileTask, notifsTask, securityTask, appearanceTask);

            _profile = profileTask.Result;
            _notificationPrefs = notifsTask.Result;
            _securitySettings = securityTask.Result;
            _appearanceSettings = appearanceTask.Result;
        }
        catch (Exception ex)
        {
            ShowToast($"Failed to load settings: {ex.Message}", isError: true);
        }
        finally
        {
            _isLoading = false;
        }
    }

    private async Task HandleSaveProfile(UserProfile profile)
    {
        try
        {
            await SettingsService.SaveProfileAsync(profile);
            _profile = profile;
            ShowToast("Profile saved successfully.");
        }
        catch (Exception ex)
        {
            ShowToast($"Failed to save profile: {ex.Message}", isError: true);
        }
    }

    private async Task HandleSaveNotifications(NotificationPrefs prefs)
    {
        try
        {
            await SettingsService.SaveNotificationPrefsAsync(prefs);
            _notificationPrefs = prefs;
            ShowToast("Notification preferences saved.");
        }
        catch (Exception ex)
        {
            ShowToast($"Failed to save notifications: {ex.Message}", isError: true);
        }
    }

    private async Task HandleChangePassword((string CurrentPassword, string NewPassword) args)
    {
        await SettingsService.ChangePasswordAsync(args.CurrentPassword, args.NewPassword);
    }

    private async Task HandleRevokeSession(string sessionId)
    {
        try
        {
            await SettingsService.RevokeSessionAsync(sessionId);
            _securitySettings = await SettingsService.GetSecuritySettingsAsync();
            ShowToast("Session revoked successfully.");
        }
        catch (Exception ex)
        {
            ShowToast($"Failed to revoke session: {ex.Message}", isError: true);
        }
    }

    private async Task HandleSaveAppearance(AppearanceSettings settings)
    {
        try
        {
            await SettingsService.SaveAppearanceAsync(settings);
            _appearanceSettings = settings;
            ShowToast("Appearance settings saved.");
        }
        catch (Exception ex)
        {
            ShowToast($"Failed to save appearance: {ex.Message}", isError: true);
        }
    }

    private void ShowToast(string message, bool isError = false)
    {
        _toastMessage = message;
        _toastIsError = isError;
    }

    private void DismissToast()
    {
        _toastMessage = null;
    }
}

